// pages/CategoryGalleryPage.js
import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import axios from "axios";

const CategoryGalleryPage = () => {
  const { section, category } = useParams();
  const [images, setImages] = useState([]);

  useEffect(() => {
    const fetchImages = async () => {
      try {
        const res = await axios.get(`http://localhost:5000/api/gallery`);
        const filtered = res.data.filter(
          (img) =>
            img.Category?.name?.toLowerCase().replace(/\s+/g, "-") === category &&
            img.Category?.section?.toLowerCase().replace(/\s+/g, "-") === section
        );
        setImages(filtered);
      } catch (err) {
        console.error("Error loading images", err);
      }
    };

    fetchImages();
  }, [section, category]);

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4 capitalize">
        {section} / {category}
      </h2>

      {images.length === 0 ? (
        <p>No images found for this category.</p>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
          {images.map((img) => (
            <div key={img.id} className="bg-white rounded shadow p-2">
              <img
                src={`http://localhost:5000${img.imageUrl}`}
                alt={img.title}
                className="w-full h-64 object-cover rounded"
              />
              <p className="text-center mt-2 font-medium">{img.title}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default CategoryGalleryPage;
